#!/usr/bin/env bash
# Generated by Agent: IMPLEMENT | Feature: EVOL-013
# ============================================================================
# check-governance-drift.sh — PreToolUse hook: warn on governance snapshot drift
# ============================================================================
# Compares MD5 hashes of docs/constitution.md and docs/setup.md against the
# hashes stored in .context/governance_snapshot.md frontmatter.
# If they diverge, emits a WARNING (non-blocking) so the agent regenerates
# the snapshot before relying on stale governance context.
#
# Non-blocking (exit 0 always) because blocking would prevent the agent from
# writing the regenerated snapshot — creating a circular dependency.
#
# Portability: works on both Linux (md5sum) and macOS (md5 -q / openssl md5).
# Uses awk for frontmatter parsing (portable across GNU/BSD).
# ============================================================================

set -euo pipefail

REPO_ROOT=$(git rev-parse --show-toplevel 2>/dev/null || echo '')
if [ -z "$REPO_ROOT" ]; then
  exit 0
fi

SNAPSHOT="$REPO_ROOT/.context/governance_snapshot.md"
CONSTITUTION="$REPO_ROOT/docs/constitution.md"
SETUP_DOC="$REPO_ROOT/docs/setup.md"

# ── Guard: skip if project not yet initialized ──────────────────────────
if [ ! -f "$CONSTITUTION" ] || [ ! -f "$SNAPSHOT" ]; then
  exit 0
fi

# ── Portable MD5 helper ─────────────────────────────────────────────────
# Returns just the hex digest. Falls back gracefully — if no tool found,
# outputs empty string and the script exits 0 (non-blocking).
compute_md5() {
  local file="$1"
  if command -v md5sum >/dev/null 2>&1; then
    md5sum "$file" 2>/dev/null | cut -d' ' -f1
  elif command -v md5 >/dev/null 2>&1; then
    md5 -q "$file" 2>/dev/null
  elif command -v openssl >/dev/null 2>&1; then
    openssl md5 "$file" 2>/dev/null | awk '{print $NF}'
  else
    echo ''
  fi
}

# ── Extract hashes from snapshot frontmatter (portable awk) ─────────────
# Frontmatter is YAML between --- delimiters at top of file.
extract_frontmatter_value() {
  local file="$1" key="$2"
  awk -v key="$key" '
    BEGIN { in_fm = 0; seen = 0 }
    /^---$/ { seen++; if (seen == 1) { in_fm = 1; next } if (seen == 2) exit }
    in_fm && $0 ~ "^" key ":[[:space:]]*" {
      value = $0
      sub("^" key ":[[:space:]]*", "", value)
      gsub(/^"|"$/, "", value)
      print value
      exit
    }
  ' "$file"
}

SNAP_CONST_HASH=$(extract_frontmatter_value "$SNAPSHOT" "constitution_hash")
SNAP_SETUP_HASH=$(extract_frontmatter_value "$SNAPSHOT" "setup_hash")

# If snapshot has no constitution_hash, it's malformed — skip silently
if [ -z "$SNAP_CONST_HASH" ]; then
  exit 0
fi

# ── Compute current hashes ───────────────────────────────────────────────
CURRENT_CONST_HASH=$(compute_md5 "$CONSTITUTION")

# If hash tool unavailable, skip silently (non-blocking)
if [ -z "$CURRENT_CONST_HASH" ]; then
  exit 0
fi

CURRENT_SETUP_HASH=""
if [ -f "$SETUP_DOC" ]; then
  CURRENT_SETUP_HASH=$(compute_md5 "$SETUP_DOC")
fi

# ── Compare and warn on drift ────────────────────────────────────────────
DRIFT_SOURCES=()

if [ "$SNAP_CONST_HASH" != "$CURRENT_CONST_HASH" ]; then
  DRIFT_SOURCES+=("constitution.md")
fi

# Setup hash comparison: only if both exist or snapshot recorded one
if [ -n "$SNAP_SETUP_HASH" ] && [ "$SNAP_SETUP_HASH" != "null" ]; then
  if [ "$SNAP_SETUP_HASH" != "$CURRENT_SETUP_HASH" ]; then
    DRIFT_SOURCES+=("setup.md")
  fi
fi

if [ ${#DRIFT_SOURCES[@]} -gt 0 ]; then
  JOINED="${DRIFT_SOURCES[0]}"
  for source in "${DRIFT_SOURCES[@]:1}"; do
    JOINED+=", ${source}"
  done
  echo "WARNING: Governance snapshot drift detected — ${JOINED} changed since last snapshot generation."
  echo "  The governance context in .context/governance_snapshot.md is STALE."
  echo "  Action: Execute GCRP Step 1 → POST-LOAD (full reload + inline snapshot regeneration)."
  echo "  This does NOT require SETUP. Read the generate_governance_snapshot() function in"
  echo "  .claude/skills/factory-governance-loading/SKILL.md and regenerate the snapshot in-place."
  # Non-blocking: exit 0 so the agent can still operate and fix the drift
fi

exit 0
